    {
        _statusStrip = new StatusStrip();
        // .NET 9 breaking change: StatusStrip default renderer changed.
        // Explicitly set RenderMode to preserve .NET 8 appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.ManagerRenderMode;
        Controls.Add(_statusStrip);
    }

    /// <summary>
    /// Wraps DropDownControl with a null guard.
    /// .NET 9 breaking change: passing null now throws ArgumentNullException.
    /// </summary>
    public static void SafeDropDown(IWindowsFormsEditorService editorService, Control control)
    {
        if (control is null)
            return;

        editorService.DropDownControl(control);
    }
}

